+    mk("banded",             BANDED_ATTENTION_WGSL,         bgls.banded),
+    mk("routerTopk",         ROUTER_TOPK_WGSL,              bgls.routerTopk),
+    mk("swiglu",             SWIGLU_CLAMP_WGSL,             bgls.swiglu),
+    mk("qmoeGateUp",         QMOE_GATE_UP_WGSL,             bgls.qmoeGateUp),
